enum _EventSuccessStrictSurface {
  companion,
  defaults,
  eventPreview,
  featureBlocks,
  host,
  lab,
  liveReveal,
  manualQa,
  questionnaire,
  setup,
  structure,
}

Widget _eventSuccessStrictPreview(
  BuildContext context, {
  required _EventSuccessStrictSurface surface,
  required String componentName,
}) {
  return switch (surface) {
    _EventSuccessStrictSurface.companion => eventSuccessCompanionScreenStates(
      context,
    ),
    _EventSuccessStrictSurface.defaults => _StrictCoverageScaffold(
      componentName: componentName,
      child: EventSuccessDefaultsPanel(
        defaults: EventSuccessDefaults.recommendedForActivity(
          ActivityKind.socialRun,
          enabled: true,
          targetAttendeeCount: 24,
          attendeePrompt: "Ask three people what made them choose this event.",
        ),
        activityKind: ActivityKind.socialRun,
        targetAttendeeCount: 24,
        onChanged: (_) {},
        title: context.l10n.hostsEventSuccessStepTitleLiveEventGuide,
        subtitle: context.l10n.hostsEventSuccessStepSubtitleSaveASimplePlan,
      ),
    ),
    _EventSuccessStrictSurface.eventPreview => _StrictCoverageScaffold(
      componentName: componentName,
      fullBleed: true,
      child: EventSuccessEventPreviewScreen(
        event: EventSuccessCompanionFixtures.socialEvent,
        userProfile: EventSuccessCompanionFixtures.viewer,
        roster: EventParticipationRoster.fromParticipations([
          EventSuccessCompanionFixtures.attendedParticipation(),
        ]),
        now: EventSuccessCompanionFixtures.now,
      ),
    ),
    _EventSuccessStrictSurface.featureBlocks => _StrictCoverageScaffold(
      componentName: componentName,
      child: const Column(
        crossAxisAlignment: CrossAxisAlignment.stretch,
        children: [
          EventSuccessHostSetupFlow(),
          gapH16,
          EventSuccessLiveHostMode(),
          gapH16,
          EventSuccessAttendeeCompanionPreview(),
          gapH16,
          EventSuccessPostEventReport(),
        ],
      ),
    ),
    _EventSuccessStrictSurface.host => _StrictCoverageScaffold(
      componentName: componentName,
      child: ProviderScope(child: _HostCoverageStates()),
    ),
    _EventSuccessStrictSurface.lab => const EventSuccessLabScreen(),
    _EventSuccessStrictSurface.liveReveal => _StrictCoverageScaffold(
      componentName: componentName,
      child: ProviderScope(child: _LiveRevealCoverageStates()),
    ),
    _EventSuccessStrictSurface.manualQa => const EventSuccessManualQaScreen(),
    _EventSuccessStrictSurface.questionnaire => _StrictCoverageScaffold(
      componentName: componentName,
      child: EventSuccessQuestionnaireConfigEditor(
        value: const EventSuccessQuestionnaireConfig.defaultTemplate(),
        onChanged: (_) {},
      ),
    ),
    _EventSuccessStrictSurface.setup => _StrictCoverageScaffold(
      componentName: componentName,
      child: EventSuccessSetupBody(
        draft: EventSuccessHostDraft.fromPlaybook(
          EventSuccessPlaybookLibrary.socialRun,
          targetAttendeeCount: 24,
        ),
        eventFormat: EventFormatSnapshot.fromActivityKind(
          ActivityKind.socialRun,
        ),
        targetAttendeeCount: 24,
        attendeePrompt:
            "Notice who arrived solo and make the first hello easy.",
        onDraftChanged: (_) {},
        onAttendeePromptChanged: (_) {},
        showResetToRecommended: true,
        onResetToRecommended: () {},
      ),
    ),
    _EventSuccessStrictSurface.structure => _StrictCoverageScaffold(
      componentName: componentName,
      child: EventSuccessStructureConfigEditor(
        value: const EventSuccessStructureConfig(
          unitKind: EventSuccessUnitKind.pods,
          unitSize: 4,
          unitCount: 3,
          rotationIntervalMinutes: 15,
          revealCountdownSeconds: 10,
        ),
        targetAttendeeCount: 24,
        enabled: true,
        onChanged: (_) {},
      ),
    ),
  };
}

class _HostCoverageStates extends StatelessWidget {
  const _HostCoverageStates();

  @override
  Widget build(BuildContext context) {
    final event = EventSuccessCompanionFixtures.socialEvent;
    final plan = EventSuccessCompanionFixtures.revealUnlockedPlan;
    final roster = EventParticipationRoster.fromParticipations([
      EventSuccessCompanionFixtures.attendedParticipation(),
    ]);
    final actions = EventSuccessHostFixtureActions(
      onSaveSetup: () {},
      onPreviousStep: () {},
      onNextStep: () {},
      onCompletePlan: () {},
      onGenerateMicroPods: () {},
      onGenerateGuidedRotations: () {},
      onOverrideGroupAssignments: (_) {},
      onOverrideGuidedRotations: (_) {},
      onStartRevealCountdown: (_, _) {},
      onRevealRound: (_) {},
      onResetReveal: () {},
    );

    return Column(
      crossAxisAlignment: CrossAxisAlignment.stretch,
      children: [
        EventSuccessHostSectionSkeleton(),
        gapH16,
        for (final tab in EventSuccessHostTab.values) ...[
          EventSuccessHostPanel(
            event: event,
            plan: plan,
            planIsPersisted: true,
            roster: roster,
            assignments: [
              EventSuccessCompanionFixtures.microPodAssignment,
              EventSuccessCompanionFixtures.tableAssignment,
            ],
            assignmentParticipantProfiles: EventSuccessCompanionFixtures.peers,
            rotationAssignments: [
              EventSuccessCompanionFixtures.rotationAssignment,
            ],
            rotationParticipantProfiles: EventSuccessCompanionFixtures.peers,
            wingmanRequests: [EventSuccessCompanionFixtures.wingmanRequest],
            wingmanProfiles: const [EventSuccessCompanionFixtures.peer],
            initialTab: tab,
            showTabs: false,
            fixtureActions: actions,
          ),
          if (tab != EventSuccessHostTab.values.last) gapH16,
        ],
      ],
    );
  }
}

class _LiveRevealCoverageStates extends StatelessWidget {
  const _LiveRevealCoverageStates();

  @override
  Widget build(BuildContext context) {
    final event = EventSuccessCompanionFixtures.racketEvent;
